// Combine Hebrew and English pages
const hePages = $('Get Hebrew Pages').item.json;
const enPages = $('Get English Pages').item.json;

// Combine all pages
const allPages = [...hePages, ...enPages];

// Create analysis data
const analysisData = {
  total_pages: allPages.length,
  hebrew_pages: hePages.length,
  english_pages: enPages.length,
  pages: allPages.map(page => ({
    id: page.id,
    slug: page.slug,
    title: page.title.rendered || page.title,
    link: page.link,
    modified: page.modified,
    language: hePages.find(p => p.id === page.id) ? 'he' : 'en'
  })),
  last_modified: allPages.reduce((latest, page) => {
    return new Date(page.modified) > new Date(latest) ? page.modified : latest;
  }, '1970-01-01T00:00:00Z')
};

return [{
  json: analysisData
}];

values.content:
You are a senior content strategist for tax4us.co.il (Israeli tax advisory).
Analyze the provided pages and suggest internal link opportunities and FAQ additions.

Return STRICT JSON array with this structure:
[
  {
    "slug": "page-slug",
    "suggested_links": [
      {"anchor": "relevant text", "to_slug": "target-page-slug"}
    ],
    "faq_additions": [
      {"q": "Question text", "a_html": "<p>Answer text</p>"}
    ]
  }
]

Guidelines:
- Suggest natural, contextual internal links
- Focus on tax-related topics and services
- Ensure anchor text is relevant and descriptive
- FAQ questions should address common tax concerns
- Keep suggestions practical and actionable

