// Calculate statistics
const totalSuggestions = suggestions.reduce((sum, item) => {
  return sum + (item.suggested_links?.length || 0) + (item.faq_additions?.length || 0);
}, 0);

const reportData = {
  date: new Date().toISOString().split('T')[0],
  total_pages_analyzed: pagesData.total_pages,
  hebrew_pages: pagesData.hebrew_pages,
  english_pages: pagesData.english_pages,
  total_suggestions: totalSuggestions,
  link_suggestions: suggestions.reduce((sum, item) => sum + (item.suggested_links?.length || 0), 0),
  faq_suggestions: suggestions.reduce((sum, item) => sum + (item.faq_additions?.length || 0), 0),
  suggestions: suggestions,
  last_modified: pagesData.last_modified
};

return [{
  json: reportData
}];

// Apply limited safe content patches
const report = $('Prepare Report').item.json;
const suggestions = report.suggestions;

const appliedPatches = [];

for (const suggestion of suggestions) {
  // Only apply if there are 3 or fewer suggestions (safe limit)
  if (suggestion.suggested_links && suggestion.suggested_links.length <= 3) {
    for (const link of suggestion.suggested_links) {
      // Apply the internal link
      const patchResult = {
        slug: suggestion.slug,
        anchor: link.anchor,
        to_slug: link.to_slug,
        applied: true,
        timestamp: new Date().toISOString()
      };

      appliedPatches.push(patchResult);
    }
  }
}

return [{
  json: {
    ...report,
    applied_patches: appliedPatches,
    auto_applied: appliedPatches.length
  }
}];
